import React, { useContext } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, Link, useLocation } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthContext } from './context/AuthContext';
import Login from './components/Login';
import Register from './components/Register';
import StudentDashboard from './components/StudentDashboard';
import AdminDashboard from './components/AdminDashboard';
import EvaluationForm from './components/EvaluationForm';
import EvaluationBuilder from './components/EvaluationBuilder';
import DataManagement from './components/DataManagement';
import CertificateGenerator from './components/CertificateGenerator';
import ProtectedRoute from './components/ProtectedRoute';
import './index.css';

function AppContent() {
  const { user, logout } = useContext(AuthContext);
  const location = useLocation();

  const isAuthPage = location.pathname === '/login' || location.pathname === '/register';

  if (isAuthPage || !user) {
    return (
      <Router>
        <Routes>
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/" element={<Navigate to="/login" />} />
        </Routes>
        <Toaster position="top-right" />
      </Router>
    );
  }

  return (
    <Router>
      <div className="flex min-h-screen bg-[#f4f6fb]">
        {/* SIDEBAR */}
        <aside className="w-[260px] bg-[#1f1f2e] text-white p-5 fixed h-full">
          <h2 className="text-xl font-bold mb-8">CMS</h2>
          <nav className="flex flex-col gap-2">
            {user.role === 'admin' ? (
              <>
                <Link to="/admin/dashboard" className={`p-3 rounded-lg hover:bg-[#2e2e44] ${location.pathname === '/admin/dashboard' ? 'bg-[#2e2e44] text-white' : ''}`}>Dashboard</Link>
                <Link to="/admin/evaluation-builder" className={`p-3 rounded-lg hover:bg-[#2e2e44] ${location.pathname === '/admin/evaluation-builder' ? 'bg-[#2e2e44] text-white' : ''}`}>Create Evaluation</Link>
                <Link to="/admin/data" className={`p-3 rounded-lg hover:bg-[#2e2e44] ${location.pathname === '/admin/data' ? 'bg-[#2e2e44] text-white' : ''}`}>Data</Link>
                <Link to="/admin/certificates" className={`p-3 rounded-lg hover:bg-[#2e2e44] ${location.pathname === '/admin/certificates' ? 'bg-[#2e2e44] text-white' : ''}`}>Certificates</Link>
              </>
            ) : (
              <>
                <Link to="/student/dashboard" className={`p-3 rounded-lg hover:bg-[#2e2e44] ${location.pathname === '/student/dashboard' ? 'bg-[#2e2e44] text-white' : ''}`}>Dashboard</Link>
              </>
            )}
          </nav>
          <button onClick={() => { logout(); window.location.href = '/login'; }} className="mt-auto p-3 rounded-lg hover:bg-[#2e2e44] w-full text-left absolute bottom-5">
            Logout
          </button>
        </aside>

        {/* MAIN */}
        <div className="ml-[260px] flex-1">
          {/* TOPBAR */}
          <header className="h-[70px] bg-white flex items-center justify-between px-6 shadow-sm">
            <h1 className="text-lg font-semibold">{user.role === 'admin' ? 'Admin Dashboard' : 'Student Dashboard'}</h1>
            <div className="flex items-center gap-3">
              <span className="font-medium">{user.fullName}</span>
              <span className="text-gray-500 text-sm capitalize">({user.role})</span>
            </div>
          </header>

          {/* CONTENT */}
          <main className="p-6">
            <Routes>
              <Route 
                path="/student/dashboard" 
                element={
                  <ProtectedRoute role="student">
                    <StudentDashboard />
                  </ProtectedRoute>
                } 
              />
              <Route 
                path="/admin/dashboard" 
                element={
                  <ProtectedRoute role="admin">
                    <AdminDashboard />
                  </ProtectedRoute>
                } 
              />
              <Route path="/evaluation/:id" element={<EvaluationForm />} />
              <Route 
                path="/admin/evaluation-builder" 
                element={
                  <ProtectedRoute role="admin">
                    <EvaluationBuilder />
                  </ProtectedRoute>
                } 
              />
              <Route 
                path="/admin/data" 
                element={
                  <ProtectedRoute role="admin">
                    <DataManagement />
                  </ProtectedRoute>
                } 
              />
              <Route 
                path="/admin/certificates" 
                element={
                  <ProtectedRoute role="admin">
                    <CertificateGenerator />
                  </ProtectedRoute>
                } 
              />
              <Route path="/" element={<Navigate to={user.role === 'admin' ? '/admin/dashboard' : '/student/dashboard'} />} />
            </Routes>
          </main>
        </div>
        <Toaster position="top-right" />
      </div>
    </Router>
  );
}

function App() {
  return <AppContent />;
}

export default App;
